// src/App.js
import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider } from './contexts/AuthContext';
import ProtectedRoute from './components/ProtectedRoute';
import AdminRoute from './components/AdminRoute';

// Import your components
import Home from './pages/Home';
import Login from './pages/Login';
import Register from './pages/Register';
import Upload from './pages/Upload';
import CourseSelection from './pages/CourseSelection';
import YearSelection from './pages/YearSelection';
import SemesterSelection from './pages/SemesterSelection';
import SubjectSelection from './pages/SubjectSelection';
import Dashboard from './pages/Dashboard';
import AdminDashboard from './pages/AdminDashboard';

function App() {
  return (
    <AuthProvider>
      <Router>
        <Routes>
          {/* Public Routes */}
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />

          {/* Protected Routes - Only for logged in users */}
          <Route path="/upload" element={
            <ProtectedRoute>
              <Upload />
            </ProtectedRoute>
          } />

          <Route path="/dashboard" element={
            <ProtectedRoute>
              <Dashboard />
            </ProtectedRoute>
          } />

          {/* Course Hierarchy Routes */}
          <Route path="/course/:courseId" element={<CourseSelection />} />
          <Route path="/course/:courseId/year/:yearId" element={<YearSelection />} />
          <Route path="/course/:courseId/year/:yearId/sem/:semesterId" element={<SemesterSelection />} />
          <Route path="/course/:courseId/year/:yearId/sem/:semesterId/subjects" element={<SubjectSelection />} />

          {/* Admin Only Routes */}
          <Route path="/admin" element={
            <AdminRoute>
              <AdminDashboard />
            </AdminRoute>
          } />

          {/* 404 Route */}
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </Router>
    </AuthProvider>
  );
}

export default App;
